            lock = ((HWREGH(DEVCFG_BASE + SYSCTL_O_ECAPTYPE) &
                     SYSCTL_ECAPTYPE_LOCK) != 0U);
            break;

        case SYSCTL_SDFMTYPE:
            lock = ((HWREGH(DEVCFG_BASE + SYSCTL_O_SDFMTYPE) &
                     SYSCTL_SDFMTYPE_LOCK) != 0U);
            break;

        default:
            break;
